"use client";

import * as React from "react";

import * as LabelPrimitive from "@radix-ui/react-label";
import { cn } from "@/lib/utils";

const Label = React.forwardRef<
	React.ElementRef<typeof LabelPrimitive.Root>,
	React.ComponentPropsWithoutRef<typeof LabelPrimitive.Root>
>(({ className, ...props }, ref) => (
	<LabelPrimitive.Root
		ref={ref}
		className={cn(
			"text-sm font-medium text-white leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70",
			className,
		)}
		{...props}
	/>
));
Label.displayName = LabelPrimitive.Root.displayName;

export { Label };

"use client";

import AnimatedPlaceholderText from "@/components/AnimatedPlaceholderText";
import { cn } from "@/lib/utils";

import React from "react";
import { motion, useMotionTemplate, useMotionValue } from "motion/react";

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
    useAnimatedPlaceholder?: boolean;
}

export const Input = React.forwardRef<HTMLInputElement, InputProps>(
    ({ className, type, useAnimatedPlaceholder, ...props }, ref) => {
        const [inputValue, setInputValue] = React.useState("");
        const radius = 100;
        const [visible, setVisible] = React.useState(false);
        const mouseX = useMotionValue(0);
        const mouseY = useMotionValue(0);

        function handleMouseMove({ currentTarget, clientX, clientY }: any) {
            const { left, top } = currentTarget.getBoundingClientRect();
            mouseX.set(clientX - left);
            mouseY.set(clientY - top);
        }

        return (
			<motion.div
				style={{
					background: useMotionTemplate`
						radial-gradient(
							${visible ? radius + "px" : "0px"} circle at ${mouseX}px ${mouseY}px,
							#FF69B4,
							transparent 80%
						)
					`,
				}}
				onMouseMove={handleMouseMove}
				onMouseEnter={() => setVisible(true)}
				onMouseLeave={() => setVisible(false)}
				className="group/input relative rounded-xl p-[2px] transition duration-300"
			>
				{useAnimatedPlaceholder && !inputValue && (
					<span className="pointer-events-none absolute left-3 top-1 text-lg text-neutral-600">
						<AnimatedPlaceholderText />
					</span>
				)}

				<input
					type={type}
					value={inputValue}
					onChange={(e) => {
						setInputValue(e.target.value);
						props.onChange?.(e);
					}}
					className={cn(
						`shadow-input placeholder:text-zinc-400
                        flex h-10 w-full rounded-xl border-none
                        px-3 py-2 text-lg transition duration-400
                        group-hover/input:shadow-none
                        file:border-0 file:bg-transparent file:text-lg file:font-medium
                        focus-visible:ring-[2px] focus-visible:outline-none
                        disabled:cursor-not-allowed disabled:opacity-50
                        bg-zinc-900 text-gray-100
                        dark:shadow-[0px_0px_2px_1px_rgba(255,105,180,0.25)]
                        focus-visible:ring-[#FF79C6]`,
						className,
					)}
					ref={ref}
					placeholder="" // keep empty
					{...props}
				/>
			</motion.div>
		);
    }
);

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

:root {
	--dracula-bg: #000000;
	--dracula-fg: #f8f8f2;
	--dracula-current: #44475a;
	--dracula-comment: #6272a4;
	--dracula-cyan: #8be9fd;
	--dracula-green: #50fa7b;
	--dracula-orange: #ffb86c;
	--dracula-pink: #ff79c6;
	--dracula-purple: #bd93f9;
	--dracula-red: #ff5555;
	--dracula-yellow: #f1fa8c;

	--radius: 0.625rem;
	--background: var(--dracula-bg);
	--foreground: var(--dracula-fg);
	--card: #000000;
	--card-foreground: var(--dracula-fg);
	--popover: var(--dracula-current);
	--popover-foreground: var(--dracula-fg);
	--primary: var(--dracula-purple);
	--primary-foreground: var(--dracula-bg);
	--secondary: var(--dracula-comment);
	--secondary-foreground: var(--dracula-fg);
	--muted: var(--dracula-current);
	--muted-foreground: var(--dracula-comment);
	--accent: var(--dracula-pink);
	--accent-foreground: var(--dracula-bg);
	--destructive: var(--dracula-red);
	--destructive-foreground: var(--dracula-fg);
	--border: var(--dracula-comment);
	--input: var(--dracula-current);
	--ring: var(--dracula-purple);

	/* Chart Colors */
	--chart-1: var(--dracula-purple);
	--chart-2: var(--dracula-cyan);
	--chart-3: var(--dracula-green);
	--chart-4: var(--dracula-orange);
	--chart-5: var(--dracula-pink);

	/* Sidebar */
	--sidebar: var(--dracula-bg);
	--sidebar-foreground: var(--dracula-fg);
	--sidebar-primary: var(--dracula-purple);
	--sidebar-primary-foreground: var(--dracula-bg);
	--sidebar-accent: var(--dracula-current);
	--sidebar-accent-foreground: var(--dracula-fg);
	--sidebar-border: var(--dracula-comment);
	--sidebar-ring: var(--dracula-purple);

	/* Scan Terminal Color Codes */
	--terminal-dns: var(--dracula-cyan);
	--terminal-subdomain: var(--dracula-green);
	--terminal-port: var(--dracula-orange);
	--terminal-error: var(--dracula-red);
	--terminal-info: var(--dracula-comment);
	--terminal-success: var(--dracula-green);
	--terminal-warning: var(--dracula-yellow);
	--terminal-tech: var(--dracula-pink);
}

/* Dark mode is the ONLY mode - no light mode */
.dark {
	/* Already dark by default */
}

@theme inline {
	--animate-scroll: scroll var(--animation-duration, 40s)
		var(--animation-direction, forwards) linear infinite;
	--color-sidebar-ring: var(--sidebar-ring);
	--color-sidebar-border: var(--sidebar-border);
	--color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
	--color-sidebar-accent: var(--sidebar-accent);
	--color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
	--color-sidebar-primary: var(--sidebar-primary);
	--color-sidebar-foreground: var(--sidebar-foreground);
	--color-sidebar: var(--sidebar);
	--color-chart-5: var(--chart-5);
	--color-chart-4: var(--chart-4);
	--color-chart-3: var(--chart-3);
	--color-chart-2: var(--chart-2);
	--color-chart-1: var(--chart-1);
	--color-ring: var(--ring);
	--color-input: var(--input);
	--color-border: var(--border);
	--color-destructive: var(--destructive);
	--color-accent-foreground: var(--accent-foreground);
	--color-accent: var(--accent);
	--color-muted-foreground: var(--muted-foreground);
	--color-muted: var(--muted);
	--color-secondary-foreground: var(--secondary-foreground);
	--color-secondary: var(--secondary);
	--color-primary-foreground: var(--primary-foreground);
	--color-primary: var(--primary);
	--color-popover-foreground: var(--popover-foreground);
	--color-popover: var(--popover);
	--color-card-foreground: var(--card-foreground);
	--color-card: var(--card);
	--color-foreground: var(--foreground);
	--color-background: var(--background);

	@keyframes scroll {
		to {
			transform: translate(calc(-50% - 0.5rem));
		}
	}

	--radius-sm: calc(var(--radius) - 4px);
	--radius-md: calc(var(--radius) - 2px);
	--radius-lg: var(--radius);
	--radius-xl: calc(var(--radius) + 4px);
	--radius-2xl: calc(var(--radius) + 8px);
	--radius-3xl: calc(var(--radius) + 12px);
	--radius-4xl: calc(var(--radius) + 16px);
}

@theme inline {
	--shadow-input:
		0px 2px 3px -1px rgba(0, 0, 0, 0.1),
		0px 1px 0px 0px rgba(25, 28, 33, 0.02),
		0px 0px 0px 1px rgba(25, 28, 33, 0.08);

	--animate-orbit: orbit calc(var(--duration) * 1s) linear infinite;
}

@keyframes orbit {
	0% {
		transform: rotate(calc(var(--angle) * 1deg))
			translateY(calc(var(--radius) * 1px))
			rotate(calc(var(--angle) * -1deg));
	}
	100% {
		transform: rotate(calc(var(--angle) * 1deg + 360deg))
			translateY(calc(var(--radius) * 1px))
			rotate(calc((var(--angle) * -1deg) - 360deg));
	}
}

@theme inline {
	--color-background: var(--background);
	--color-foreground: var(--foreground);
	--font-sans: var(--font-geist-sans);
	--font-mono: var(--font-jetbrains-mono);
}

@layer base {
	* {
		@apply border-border outline-ring/50;
	}
	body {
		@apply bg-background text-foreground;
	}
	html {
		color-scheme: dark;
	}
}

/* Terminal Styles - Chaos-like appearance */
.terminal-output {
	font-family: var(--font-jetbrains-mono), "JetBrains Mono", monospace;
	font-size: 0.875rem;
	line-height: 1.5;
	background: var(--dracula-bg);
	color: var(--dracula-fg);
}

.terminal-line {
	padding: 0.125rem 0;
}

.terminal-line-dns {
	color: var(--terminal-dns);
}

.terminal-line-subdomain {
	color: var(--terminal-subdomain);
}

.terminal-line-port {
	color: var(--terminal-port);
}

.terminal-line-error {
	color: var(--terminal-error);
}

.terminal-line-info {
	color: var(--terminal-info);
}

.terminal-line-success {
	color: var(--terminal-success);
}

.terminal-line-warning {
	color: var(--terminal-warning);
}

.terminal-line-tech {
	color: var(--terminal-tech);
}

/* Scrollbar styling for terminal */
.terminal-output::-webkit-scrollbar {
	width: 8px;
}

.terminal-output::-webkit-scrollbar-track {
	background: var(--dracula-bg);
}

.terminal-output::-webkit-scrollbar-thumb {
	background: var(--dracula-comment);
	border-radius: 4px;
}

.terminal-output::-webkit-scrollbar-thumb:hover {
	background: var(--dracula-purple);
}

::view-transition-old(root),
::view-transition-new(root) {
	animation: none;
	mix-blend-mode: normal;
}

