						icon={<IconBrandGithub className="h-5 w-5" />}
					/>
					<SocialButton
						icon={<IconBrandGoogle className="h-5 w-5" />}
					/>
					<SocialButton
						icon={<IconBrandOnlyfans className="h-5 w-5" />}
					/>
				</div>

				<p className="mt-6 text-center text-sm text-muted-foreground">
